1. 创建spark sql类型的周期任务
2. 输入正确语法的sql，
drop table if EXISTS test;
CREATE TABLE IF NOT EXISTS test(id INT COMMENT '索引',name STRING COMMENT '姓名',age SMALLINT COMMENT '年龄') COMMENT “测试表“
lifecycle 29;
TRUNCATE TABLE test;
INSERT INTO test VALUES (0,'测试',18),(2,'Jam',28),(1,'NULL',32),(5,'',27),(4,'',28),(3,NULL,21),(6,'张震岳',35),(7,'王菲',41),(8,'林二汶',25),(9,'Reol',24),(10,'杨丞琳',36),(11,'Taylor',34),(12,'Billie',22);
SELECT * FROM test;
SELECT count(name) FROM test;
SELECT * FROM test LIMIT 3;
SELECT * FROM test WHERE age > 20 order BY id desc;
show tables;
，保存并提交
3. 在周期任务管理中，选择该周期任务，补数据运行
4. 在补数据任务实例运行时/任务运行结束，进入任务实例详情，选择运行记录tab，多次上下滑动日志

